import React, { useState } from 'react';
import axios from 'axios';

const STORE_ID = '36265ff8-1750-4f6f-8ec7-4c6925e77901';
const BACKEND_URL = process.env.REACT_APP_BACKEND_URL;

function Products() {
  const [form, setForm] = useState({
    name: '',
    sku: '',
    quantity: '',
    low_stock_threshold: '',
    price: ''
  });
  const [message, setMessage] = useState('');

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${BACKEND_URL}/products`, {
        ...form,
        store_id: STORE_ID,
        quantity: parseInt(form.quantity),
        low_stock_threshold: parseInt(form.low_stock_threshold),
        price: parseFloat(form.price)
      });
      setMessage('Product added successfully!');
      setForm({ name: '', sku: '', quantity: '', low_stock_threshold: '', price: '' });
    } catch (err) {
      setMessage('Error adding product. Please try again.');
    }
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial, sans-serif' }}>
      <h1>Add New Product</h1>

      {message && (
        <div style={{ background: '#d4edda', padding: '10px', borderRadius: '8px', marginBottom: '20px' }}>
          {message}
        </div>
      )}

      <form onSubmit={handleSubmit} style={{ maxWidth: '400px' }}>
        <div style={{ marginBottom: '15px' }}>
          <label>Product Name</label><br />
          <input name="name" value={form.name} onChange={handleChange} required
            style={{ width: '100%', padding: '8px', marginTop: '5px' }} />
        </div>
        <div style={{ marginBottom: '15px' }}>
          <label>SKU</label><br />
          <input name="sku" value={form.sku} onChange={handleChange}
            style={{ width: '100%', padding: '8px', marginTop: '5px' }} />
        </div>
        <div style={{ marginBottom: '15px' }}>
          <label>Quantity</label><br />
          <input name="quantity" type="number" value={form.quantity} onChange={handleChange} required
            style={{ width: '100%', padding: '8px', marginTop: '5px' }} />
        </div>
        <div style={{ marginBottom: '15px' }}>
          <label>Low Stock Threshold</label><br />
          <input name="low_stock_threshold" type="number" value={form.low_stock_threshold} onChange={handleChange} required
            style={{ width: '100%', padding: '8px', marginTop: '5px' }} />
        </div>
        <div style={{ marginBottom: '15px' }}>
          <label>Price (KSh)</label><br />
          <input name="price" type="number" value={form.price} onChange={handleChange} required
            style={{ width: '100%', padding: '8px', marginTop: '5px' }} />
        </div>
        <button type="submit"
          style={{ background: '#28a745', color: 'white', padding: '10px 20px', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
          Add Product
        </button>
      </form>
    </div>
  );
}

export default Products;
